using System;

public class MyAttribute: Attribute // Noncompliant
{
    public string Name { get; }

    public MyAttribute(string name) =>
        Name = name;
}

[AttributeUsage(AttributeTargets.Class)]
public class DocumentationAttribute : Attribute // Noncompliant
{
    public string Description { get; }
}

compliant:
using System;

public sealed class MyAttribute : Attribute // Compliant
{
    public string Name { get; }

    public MyAttribute(string name) =>
        Name = name;
}

public abstract class BaseAttribute : Attribute // Compliant - abstract attributes don't need to be sealed
{
    protected abstract void Process();
}
